{
  "Name": "Lowest GPU Utilization",
  "Description": "Prefer the healthiest GPU-capable endpoint with the lowest utilization.",
  "MaxTelemetryAgeMs": 30000,
  "Filters": [
    { "Metric": "health.isHealthy", "Operator": "Equal", "ValueType": "Boolean", "Value": "true" },
    { "Metric": "health.hasCapacity", "Operator": "Equal", "ValueType": "Boolean", "Value": "true" },
    { "Metric": "rig.gpu.available", "Operator": "Equal", "ValueType": "Boolean", "Value": "true" }
  ],
  "Ranking": [
    { "Metric": "rig.gpu.avgUtilizationPercent", "Direction": "Ascending", "Weight": 1.0 }
  ],
  "FallbackMode": "UseLegacyLoadBalancingMode",
  "TieBreaker": "RoundRobin",
  "Active": true
}

{
  "TenantId": "{{tenantId}}",
  "Name": "Daily user cost",
  "Description": "Estimate user token cost over the last day.",
  "Query": {
    "Range": "lastDay",
    "BucketSeconds": {{analyticsBucketSeconds}},
    "TokenUnitCost": {{analyticsTokenUnitCost}},
    "CostCurrency": "{{analyticsCostCurrency}}",
    "GroupBy": [
      "RequestorUserId"
    ],
    "Filters": {
      "RequestorUserIds": [
        "{{analyticsRequestorUserGuid}}"
      ],
      "SuccessfulCompletionsOnly": true
    },
    "Limit": {{analyticsLimit}}
  },
  "DisplayState": {
    "workspace": "Analytics",
    "chart": "VolumeAndTtft"
  },
  "Labels": [
    "analytics"
  ],
  "Tags": {
    "range": "lastDay"
  }
}

{
  "TenantId": "{{tenantId}}",
  "Name": "Daily user cost updated",
  "Description": "Updated report definition.",
  "Query": {
    "Range": "lastDay",
    "BucketSeconds": {{analyticsBucketSeconds}},
    "TokenUnitCost": {{analyticsTokenUnitCost}},
    "CostCurrency": "{{analyticsCostCurrency}}",
    "GroupBy": [
      "RequestorUserId"
    ],
    "Filters": {
      "RequestorUserIds": [
        "{{analyticsRequestorUserGuid}}"
      ],
      "SuccessfulCompletionsOnly": true
    },
    "Limit": {{analyticsLimit}}
  },
  "DisplayState": {
    "workspace": "Analytics",
    "chart": "VolumeAndTtft"
  },
  "Labels": [
    "analytics"
  ],
  "Tags": {
    "range": "lastDay"
  }
}
